// AMRIGS - Prova AMB, AMRIGS, ACM e AMMS 02/2023 - Acesso Direto e Autoavaliação
// Gabarito definitivo (pós-recursos), conforme Edital de Gabaritos Definitivos e Justificativas
export const AMRIGS_2023_QUESTIONS: any[] = [
  { id: "amrigs_2023_001", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Analise o gráfico de concentração sérica por tempo de dois antibióticos (linha contínua e linha pontilhada), considerando função renal normal. A linha contínua tem picos mais frequentes e menores intervalos de dose; a linha pontilhada tem intervalos maiores entre as doses. Os antibióticos correspondentes à linha contínua e à linha pontilhada podem ser, respectivamente:", options: ["Amoxicilina e cefuroxima.", "Ciprofloxacino e meropenem.", "Oxacilina e amicacina.", "Ampicilina e ciprofloxacino."], correctIndex: 2 },
  { id: "amrigs_2023_002", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Qual das seguintes situações clínicas apresenta um quadro mais provável de doença reumatológica em um paciente com artralgia?", options: ["Paciente de 25 anos, cefaleia recorrente, FAN 1:160, padrão citoplasmático fibrilar linear em exame de rotina.", "Paciente de 60 anos, histórico de fadiga, FAN 1:640, padrão nuclear pontilhado grosso.", "Paciente de 30 anos, em tratamento para acne com isotretinoína, com mialgias, FAN 1:320, padrão citoplasmático pontilhado polar.", "Paciente de 45 anos, histórico de infecção respiratória recente, FAN 1:160, padrão citoplasmático fibrilar filamentar."], correctIndex: 1 },
  { id: "amrigs_2023_003", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Analise as assertivas: I. A síndrome da secreção inadequada do hormônio antidiurético é uma causa de hipernatremia. II. Leucócitos superiores a 100.000 podem causar pseudo-hipercalemia. III. Hiperfosfatemia pode ser causada pela síndrome de realimentação. IV. Hipercalcemia é o distúrbio eletrolítico mais frequente nas síndromes paraneoplásicas. Quais estão corretas?", options: ["Apenas I e III.", "Apenas II e IV.", "Apenas I, II e III.", "Apenas I, II e IV."], correctIndex: 1 },
  { id: "amrigs_2023_004", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem, 48 anos, procura emergência com desconforto torácico. O eletrocardiograma apresenta padrão S1Q3T3, sugestivo de embolia pulmonar aguda. Considerando as informações apresentadas, o tratamento inicial para esse paciente é:", options: ["Anticoagulação a pleno.", "Dupla antiagregação plaquetária.", "Angioplastia coronária.", "Trombólise."], correctIndex: 0 },
  { id: "amrigs_2023_005", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Analise a figura que representa os ambientes intra e extracelular, na qual os itens 'A' e 'C' têm maiores concentrações intracelulares e o item 'B' tem maior concentração extracelular. As letras A, B e C correspondem, respectivamente, aos eletrólitos:", options: ["Cloro, potássio e sódio.", "Potássio, sódio e magnésio.", "Fosfato, cloro e sódio.", "Potássio, sódio e cloro."], correctIndex: 1 },
  { id: "amrigs_2023_006", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Analise as assertivas sobre febre maculosa: I. É causada por um vírus transmitido pela picada do carrapato-estrela. II. Os sintomas aparecem entre 2 e 14 dias após a picada. III. O tratamento é feito com medidas de suporte e sintomáticos. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas II e III.", "I, II e III."], correctIndex: 1 },
  { id: "amrigs_2023_007", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Mulher, 78 anos, prurido iniciado há pouco mais de um mês, sem outras queixas, perda não intencional de 2kg em 3 meses. Sem comorbidades ou medicações contínuas. Exames: Hemoglobina 13,1g/dL; Hematócrito 39%; Leucócitos 13.500 (1% bastões, 52% neutrófilos, 2% eosinófilos, 5% monócitos, 40% linfócitos); Plaquetas 128.000; Ferro 58; Ferritina 340; B12 >2000UI; TSH 0,8. Assinale a melhor conduta:", options: ["Prosseguir com a investigação, pois o quadro clínico é sugestivo de doença linfoproliferativa.", "Tranquilizar a paciente e orientar uso de creme hidratante para alívio do prurido.", "Repetir os exames, pois alguns achados estão incompatíveis com o caso.", "Orientar o uso de anti-histamínicos para alívio dos sintomas e avaliar a resposta."], correctIndex: 0 },
  { id: "amrigs_2023_008", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Em relação aos aspectos nutricionais da população em geral, analise: I. O uso de polivitamínicos na população idosa deve ser incentivado em todos os casos, objetivando níveis séricos supraterapêuticos e reduzindo internações. II. A dosagem sérica de albumina é o marcador ideal para avaliar o status nutricional em pacientes hospitalizados com inflamação sistêmica prolongada. III. Pacientes politraumatizados e grandes queimados necessitam aporte calórico em torno de 35 a 40 kcal/kg na fase aguda. Quais estão corretas?", options: ["Apenas I.", "Apenas III.", "Apenas I e II.", "I, II e III."], correctIndex: 1 },
  { id: "amrigs_2023_009", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Considerando o esquema vacinal do adulto e do idoso (calendário vacinal 2022), assinale a alternativa correta.", options: ["A vacina pneumocócica 23 valente está indicada para todos a partir dos 60 anos e deve ser repetida a cada 5 anos.", "As vacinas contra difteria, tétano e febre amarela são compostas por vírus vivos atenuados.", "A vacina para febre amarela deve ser feita em 2 doses com intervalo de 10 anos, até os 59 anos.", "A vacina contra difteria e tétano deve ser feita em 3 doses iniciais, com intervalo de 60 dias entre elas, e seu reforço deve ser feito em 5 anos, caso ocorram ferimentos graves."], correctIndex: 3 },
  { id: "amrigs_2023_010", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "As anormalidades no pulso venoso jugular são úteis na detecção de insuficiência cardíaca e alterações de pressão pulmonar. Relacione a Coluna 1 (1. Onda A aumentada; 2. Onda V gigante; 3. Descenso Y proeminente; 4. Descenso Y ausente) à Coluna 2 (Tamponamento cardíaco; Estenose tricúspide; Insuficiência tricúspide; Pericardite constritiva), na ordem apresentada:", options: ["3 – 2 – 1 – 4.", "2 – 4 – 3 – 1.", "4 – 2 – 3 – 1.", "4 – 1 – 2 – 3."], correctIndex: 3 },
  { id: "amrigs_2023_011", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Infectologia", text: "São sinais de alarme relacionados aos pacientes com dengue grupo C, EXCETO:", options: ["Derrame pericárdico, ascite e derrame pleural.", "Hepatomegalia e lipotimia.", "Queda do hematócrito e dor abdominal em cólica.", "Sangramento de mucosa e irritabilidade."], correctIndex: 2 },
  { id: "amrigs_2023_012", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Em relação à ascite, analise: I. Restrição de sal e água é medida fundamental para o manejo de todos os pacientes com ascite. II. A espironolactona é mais eficiente que os diuréticos de alça no seu manejo. III. Pacientes com ascite secundária à carcinomatose peritoneal devem receber reposição de albumina quando o volume da paracentese for superior a 5 litros. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas I e III.", "I, II e III."], correctIndex: 1 },
  { id: "amrigs_2023_013", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Analise: I. A regulação da maioria dos hormônios da adeno-hipófise depende de sinais estimulantes do hipotálamo; apenas a prolactina é regulada por estímulos inibitórios. II. Se a haste hipofisária for lesionada, a liberação de prolactina aumenta, ao passo que a liberação dos outros hormônios da adeno-hipófise diminui.", options: ["Todas as assertivas estão corretas.", "Todas as assertivas estão incorretas.", "Apenas a assertiva I está correta.", "Apenas a assertiva II está correta."], correctIndex: 0 },
  { id: "amrigs_2023_014", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "A dupla antiagregação plaquetária deve ser mantida: I. Indefinidamente para pacientes com doença arterial periférica aterosclerótica. II. Por pelo menos 12 meses após episódio de infarto agudo do miocárdio com angioplastia percutânea primária. III. Indefinidamente em pacientes diabéticos que tiveram um episódio cerebrovascular isquêmico. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas I e II.", "I, II e III."], correctIndex: 1 },
  { id: "amrigs_2023_015", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Nos casos de asma brônquica em que o corticoide inalatório não está sendo suficiente para controle dos sintomas, deve-se fazer uso de:", options: ["Corticoide oral.", "Montelucaste.", "Beta-2-agonista de longa duração.", "Tiotrópio."], correctIndex: 2 },
  { id: "amrigs_2023_016", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Recomenda-se que as pessoas com risco médio para câncer colorretal iniciem o rastreamento regular aos ____ anos. As pessoas em bom estado geral de saúde e expectativa de vida de mais de 10 anos devem manter o rastreamento regularmente até os ____ anos de idade. Assinale a alternativa que preenche corretamente as lacunas:", options: ["40 – 75", "45 – 75", "45 – 70", "50 – 75"], correctIndex: 3 },
  { id: "amrigs_2023_017", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Em relação à terapia antirretroviral para o tratamento do HIV, os pacientes que apresentam febre ou exantema durante exposição prévia podem desenvolver reações de hipersensibilidade intensa e potencialmente fatal caso ocorra a reexposição ao medicamento:", options: ["Abacavir.", "Dolutegravir.", "Efavirenz.", "Rilpivirina."], correctIndex: 0 },
  { id: "amrigs_2023_018", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "O quelante recomendado para uso em envenenamento crônico por mercúrio em adultos é:", options: ["Deferoxamina.", "Azul da Prússia.", "Ácido dimercaptossuccínico.", "Ácido etilenodiaminotetracético."], correctIndex: 2 },
  { id: "amrigs_2023_019", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Analise: I. Condições médicas gerais, como esclerose múltipla e hipertireoidismo, podem induzir ou mimetizar sintomas de humor. II. A farmacoterapia é a principal modalidade terapêutica no transtorno bipolar. III. TSH, prolactina e creatinina sérica fazem parte da avaliação clínico-laboratorial no transtorno bipolar prévia ao se introduzir psicofármacos. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas I e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_020", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Homem, 66 anos, apresenta quadro demencial com flutuações cognitivas, quedas, fraqueza de membros, alucinações visuais vívidas, inversão do ciclo sono-vigília com sono agitado e distúrbio comportamental do sono REM. A descrição refere-se a qual tipo de demência?", options: ["Alzheimer.", "Com corpúsculos de Lewy.", "Frontotemporal.", "Parkinson."], correctIndex: 1 },
  { id: "amrigs_2023_021", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Sobre a classificação de Mascarenhas da acalásia do esôfago, assinale a alternativa correta.", options: ["Tem subclassificação em seis subtipos e sua variação é conforme a pressão de fechamento do esfíncter esofágico inferior.", "Independentemente da classificação, o tratamento cirúrgico é a primeira opção de escolha.", "A classe II é caracterizada por dilatação entre 4 e 7 centímetros.", "O diagnóstico etiológico mais comum no Brasil é acalásia secundária à doença de Chagas."], correctIndex: 2 },
  { id: "amrigs_2023_022", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Em relação aos critérios de Ranson para pancreatite aguda biliar, assinale a alternativa INCORRETA.", options: ["Após 48 horas de internação do paciente, os critérios são diferentes dos avaliados na chegada do quadro clínico/laboratorial.", "Durante avaliação na chegada, critérios clínicos/laboratoriais como idade, leucograma e glicemia são avaliados.", "Fatores como PaO2, Desidrogenase Láctica (LDH) e Transaminase Pirúvica (TGP) são avaliados após 48 horas.", "Não incluem avaliação por exame de imagem."], correctIndex: 2 },
  { id: "amrigs_2023_023", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "NÃO é um fator de risco para câncer gástrico:", options: ["Cirurgia gástrica prévia.", "Tipo sanguíneo A.", "Diabetes melito.", "Tabagismo."], correctIndex: 2 },
  { id: "amrigs_2023_024", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Conforme a localização de uma úlcera gástrica, podemos classificá-la e correlacioná-la com a produção de cloro. Sobre a classificação da doença ulcerosa péptica, assinale a alternativa correta.", options: ["Tipo I: úlcera de qualquer localização associada ao uso de AINE.", "Tipo III: úlcera de localização pré-pilórica e está relacionada à hipercloridria.", "Tipo IV: úlcera próxima à cárdia, e está associada à hipercloridria.", "Tipo V: úlcera de localização de pequena curvatura e está associada ao uso de AINE."], correctIndex: 1 },
  { id: "amrigs_2023_025", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Em relação ao divertículo de Zenker, assinale a alternativa correta.", options: ["É encontrado no esôfago distal.", "É o segundo divertículo mais comum na topografia esofágica.", "Divertículos pequenos, principalmente menores que 1-2 cm, costumam ser assintomáticos.", "A ressecção do divertículo é opção cirúrgica adotada em casos assintomáticos."], correctIndex: 2 },
  { id: "amrigs_2023_026", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "NÃO são fatores de risco de infecção em mordedura por animal:", options: ["Paciente com idade menor do que quatorze anos, hiperesplenismo e hipocolesterolemia.", "Ocorrência em locais como mãos, pés e punhos.", "Paciente com idade acima de cinquenta anos, insuficiência vascular periférica e alcoolismo crônico.", "Doenças metabólicas e asplenismo."], correctIndex: 0 },
  { id: "amrigs_2023_027", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Sobre o diagnóstico de abdome agudo, assinale a alternativa INCORRETA.", options: ["É classificado em cinco subtipos: inflamatório, hemorrágico, isquêmico, obstrutivo e perfurativo.", "Na prática clínica, se não diagnosticado em tempo hábil, evolui para abdome agudo perfurativo, quadros iniciais de abdome agudo inflamatório e obstrutivo.", "Entre as causas cirúrgicas de abdome agudo, está a úlcera péptica perfurada em paciente instável hemodinamicamente, hiponatremia, uremia e apendicite aguda.", "O abdome agudo obstrutivo por causa benigna tem como etiologia mais comum bridas intestinais, seguida por hérnias inguinais ou de parede abdominal."], correctIndex: 2 },
  { id: "amrigs_2023_028", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a alternativa correta em relação aos sinais apresentados durante o exame físico abdominal.", options: ["Sinal de Murphy: dor à inspiração profunda durante a palpação abdominal, localizado em hipocôndrio esquerdo.", "Sinal de Courvoisier: vesícula biliar palpável em paciente com icterícia.", "Sinal de Cullen: equimose em região de abdome superior ao diagnóstico de úlcera péptica perfurada.", "Sinal de Ten Horn: dor à tração suave de bolsa testicular esquerda em suspeita de urolitíase."], correctIndex: 1 },
  { id: "amrigs_2023_029", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Em relação à doença ulcerosa péptica, assinale a alternativa correta com base na classificação de Forrest.", options: ["IIb: aqueles que têm coágulo aderente à ulceração e possuem risco intermediário de novo sangramento.", "Ia: aqueles que têm lesão ulcerosa limpa, com baixa possibilidade de sangramento.", "IIc: aqueles que apresentam vaso visível, porém não sangrante e têm alto risco de sangramento.", "III: aqueles que têm hemorragia ativa e apresentam alto risco de novo episódio de sangramento no futuro."], correctIndex: 0 },
  { id: "amrigs_2023_030", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Sobre a hemorragia digestiva baixa, assinale a alternativa INCORRETA.", options: ["É um diagnóstico menos frequente do que a hemorragia digestiva alta.", "A causa mais comum de hemorragia digestiva baixa colônica é a diverticulite aguda.", "A causa mais comum de sangramento de intestino delgado é a doença de Crohn.", "Colite, ou proctite secundária à radioterapia, constitui uma das causas mais incomuns de sangramento baixo, correspondendo a aproximadamente um a três por cento."], correctIndex: 1 },
  { id: "amrigs_2023_031", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Em relação à resposta hormonal ao estresse cirúrgico, é INCORRETO afirmar que:", options: ["A drenagem de cortisol está aumentada.", "A drenagem de insulina está aumentada.", "A drenagem de aldosterona está aumentada.", "A drenagem de glucagon está aumentada."], correctIndex: 1 },
  { id: "amrigs_2023_032", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Considera-se um fator de risco associado à ventilação mecânica pós-operatória:", options: ["Nível de albumina <2,2 mg/dl.", "Idade maior ou igual a 80 anos.", "Insuficiência renal aguda.", "Ventilação mecânica por uma semana."], correctIndex: 0 },
  { id: "amrigs_2023_033", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "São antibióticos que exigem ajuste de dose por insuficiência hepática ou renal, EXCETO:", options: ["Meropenem.", "Metronidazol.", "Vancomicina.", "Azitromicina."], correctIndex: 3 },
  { id: "amrigs_2023_034", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "O retroperitônio é dividido em três zonas. Assinale a alternativa correta sobre a divisão do retroperitônio observada na cirurgia laparotômica.", options: ["A zona um compreende as estruturas vasculares centrais.", "A zona dois é a que compreende a vascularização pélvica.", "A zona dois compreende o arco duodenal e a cabeça pancreática.", "A zona três é a que compreende a loja renal bilateral."], correctIndex: 0 },
  { id: "amrigs_2023_035", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "São fatores perioperatórios que influenciam a rejeição de tela inabsorvível durante a reconstrução de uma parede abdominal em cirurgias de hérnias complexas, EXCETO:", options: ["Utilização de fios absorvíveis, como de polipropileno, para fixação da tela.", "Interrupção do tabagismo.", "Antissépticos utilizados para higiene de sítio cirúrgico.", "Evitar contato da tela com a pele."], correctIndex: 0 },
  { id: "amrigs_2023_036", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "A classificação de Spigelman é utilizada para melhor avaliação da adenomatose duodenal. Sobre esse assunto, assinale a alternativa correta.", options: ["A classificação tem cinco parâmetros, sendo um deles o número de adenomas encontrados.", "O tamanho do pólipo é medido em milímetros, sendo um pólipo maior que 10 mm classificado como três pontos.", "A classificação pode variar entre 0 e 25 pontos.", "A histologia do adenoma não é considerada, diferentemente do avaliado no cólon, por exemplo."], correctIndex: 1 },
  { id: "amrigs_2023_037", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Sobre o sistema TNM de classificação dos tumores malignos encontrados no intestino delgado, é correto afirmar que:", options: ["Uma lesão classificada como T3 tem tamanho entre cinco e dez centímetros.", "Uma lesão considerada N0 tem linfonodos regionais positivos.", "Uma lesão classificada como T4 tem menos de dez centímetros.", "Uma lesão classificada como N1 tem linfonodos positivos a distância."], correctIndex: 0 },
  { id: "amrigs_2023_038", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a alternativa correta sobre a anatomia vascular do cólon.", options: ["O cólon sigmoide é vascularizado pela artéria mesentérica superior.", "O cólon ascendente é vascularizado pela artéria mesentérica superior.", "O cólon direito é vascularizado pela artéria cólica direita, que existe em todos os pacientes.", "O cólon esquerdo é vascularizado pela artéria cólica esquerda, ramo da artéria mesentérica superior."], correctIndex: 1 },
  { id: "amrigs_2023_039", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "O cirurgião deve ser muito criterioso na indicação de procedimento cirúrgico para a doença de Crohn. São motivos de indicação de cirurgia, EXCETO:", options: ["Fístula.", "Obstrução intestinal.", "Megacólon tóxico.", "Hemorragia controlada com tratamento conservador."], correctIndex: 3 },
  { id: "amrigs_2023_040", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Sobre os diagnósticos diferenciais na elucidação diagnóstica das massas ovarianas, é INCORRETO afirmar que:", options: ["Entre as patologias malignas, encontra-se carcinoma invasivo de células claras, carcinoma invasivo endometrial, entre outros.", "Entre as patologias benignas do ovário, encontra-se o corpo lúteo hemorrágico e o endometrioma, entre outros.", "Entre as metástases, podemos encontrar do câncer de cólon, de estômago, linfoma, entre outros.", "Quando realizado o diagnóstico de gravidez ectópica, o tratamento optado sempre será o cirúrgico."], correctIndex: 3 },
  { id: "amrigs_2023_041", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "São causas incomuns (<12%) de sangramento pós-menopausa: I. Atrofia endometrial. II. Pólipos endometriais. III. Câncer de endométrio. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas II e III.", "I, II e III."], correctIndex: 2 },
  { id: "amrigs_2023_042", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Deve-se investigar a amenorreia primária nos seguintes casos: I. Em meninas com mais de 15 anos de idade, com caracteres sexuais secundários presentes. II. Na ausência de menarca após 5 anos do início da telarca. III. Em meninas com 13 anos de idade sem caracteres secundários. Quais estão corretos?", options: ["Apenas I.", "Apenas II.", "Apenas I e II.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_043", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 22 semanas, vem para consulta na unidade de Atenção Básica. Ela não apresenta queixas e o exame físico não apresenta anormalidades. A próxima consulta do pré-natal deve ser marcada em:", options: ["7 dias.", "15 dias.", "20 dias.", "30 dias."], correctIndex: 3 },
  { id: "amrigs_2023_044", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Nulípara de 25 anos vem à consulta porque parou de usar anticoncepcional há 6 meses e ainda não conseguiu engravidar. Ciclos a cada 26-30 dias. Nega antecedentes de ISTs. Usa maconha para relaxar à noite e toma pelo menos 5 xícaras de café (575mg cafeína) ao dia. PA 110/70mmHg, IMC 28. O médico tranquilizou a paciente e disse que ela deveria esperar 1 ano para iniciar a investigação de infertilidade, sem mudar mais nada. A conduta do médico está:", options: ["Correta em todos os aspectos.", "Parcialmente correta, pois ele deveria ter recomendado a redução do peso e iniciar terapias cognitivas para o cansaço, mantendo os demais aspectos da vida.", "Parcialmente correta, pois deveria tê-la aconselhado a buscar um IMC de 24, a cessar o uso da maconha e diminuir o consumo de café para 1 xícara por dia.", "Incorreta em todos os aspectos, pois deveria ter encaminhado a paciente para um serviço de infertilidade, já que, após 6 meses de relações desprotegidas, mais de 85% das mulheres engravidam."], correctIndex: 2 },
  { id: "amrigs_2023_045", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "A posição da JEC (Junção Escamocolunar), em relação ao eixo longitudinal do colo do útero, depende da idade e do status hormonal da mulher. Um colo no qual a JEC se encontra mais internalizada no canal cervical é típico de uma mulher com:", options: ["12 anos (puberdade).", "21 anos (menacme, nulípara).", "21 anos (menacme, multípara).", "50 anos ou mais (menopausa)."], correctIndex: 3 },
  { id: "amrigs_2023_046", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 23 anos, vem à consulta porque notou, há 1 semana, uma lesão não pruriginosa na vulva: pápula única, rosada, com depressão central semelhante a um umbigo, não dolorosa. O diagnóstico mais provável é:", options: ["Molusco contagioso.", "Pediculose.", "Condiloma.", "Cancro duro."], correctIndex: 0 },
  { id: "amrigs_2023_047", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Após o desprendimento do feto, a ligadura do cordão é realizada. A recomendação correta da ligadura inclui:", options: ["Realizar o clampeamento cerca de 1 cm do abdome fetal ou menos, usando duas pinças.", "Utilizar somente uma pinça de clampeamento e seccionar na posição a jusante do feto.", "Utilizar somente uma pinça de clampeamento e seccionar na posição a montante do feto.", "Postergar o clampeamento cerca de 30 a 60 segundos após o parto em recém-nascidos vigorosos a termo e pré-termo."], correctIndex: 3 },
  { id: "amrigs_2023_048", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Um estudo (2014) investigou se a endometriose era uma doença progressiva, com hipótese de correlação positiva entre idade e estadiamento. Coorte com 500 casos, dotplot com ANOVA p=0,9 e correlação de Spearman r=-0,023 (IC95% = -0,12 a 0,08, n=364). Com base nesses dados, assinale a alternativa correta.", options: ["Os resultados confirmaram que a endometriose é uma doença progressiva. O estadiamento aumenta com o avançar da idade.", "O estadiamento da endometriose reduz com o aumento da idade, pois a paciente está mais próxima da menopausa.", "Foi possível demonstrar a correlação positiva em 90% (p=0,9), confirmado no curto intervalo de confiança de r.", "Não foi possível demonstrar a correlação positiva entre a idade e o estadiamento da endometriose."], correctIndex: 3 },
  { id: "amrigs_2023_049", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 45 anos foi submetida à histerectomia total por miomatose. No pós-operatório imediato, prescreveu-se quetamina, cetorolaco, ibuprofeno e 1mg de morfina IV até de 3/3h se dor forte. Após algumas horas, a paciente começou a ter alucinações. Para corrigir essa prescrição, o médico deve: I. Suspender ou reduzir a dose de quetamina, provável causa das alucinações. II. Escolher apenas uma das drogas anti-inflamatórias, pois há sobreposição de cetorolaco e ibuprofeno. III. Acrescentar gabapentina para reduzir a necessidade de opioides. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas I e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_050", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Uma mãe traz sua filha de 12 anos para saber se ela precisa tomar a vacina para o HPV; a filha ainda não iniciou atividade sexual. Segundo o Programa Nacional de Imunização, o médico deve recomendar:", options: ["Uma dose da vacina para a filha, após um resultado negativo para pesquisa do HPV.", "Três doses entre 9 e 14 anos, uma a cada ano.", "Uma dose da vacina quadrivalente no dia da consulta e outra em 6 meses.", "Que use preservativo em todas as relações, pois a sua filha já passou da época de receber a vacina para o HPV."], correctIndex: 2 },
  { id: "amrigs_2023_051", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "O gráfico dos níveis de hCG após um evento em que um saco gestacional foi identificado dentro do útero mostra queda de valor inicial de cerca de 2000mUI/mL para próximo de zero no 7º dia. A linha do hCG representa, mais provavelmente, um caso de:", options: ["Aborto em curso.", "Aborto incompleto.", "Aborto completo.", "Gravidez ectópica."], correctIndex: 2 },
  { id: "amrigs_2023_052", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "O critério diagnóstico para pré-eclâmpsia é 'pressão sistólica maior ou igual a 140mmHg e/ou pressão arterial igual ou superior a 90mmHg, verificada em 2 tomadas (intervalo de pelo menos 4 horas), após a 20ª semana de gestação, em mulheres com pressão arterial prévia normal' e associado a: I. Proteinúria acima de 300mg em 24 horas. II. Creatinina no soro maior que 1,1mg/dl. III. Elevação das transaminases em duas vezes a sua concentração. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas I e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_053", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Em relação à incontinência ou insuficiência cervical, a cerclagem está indicada nos casos a seguir, EXCETO:", options: ["Após uma perda fetal, com quadro clínico de insuficiência cervical; exame transvaginal do colo indicado a partir de 16 a 24 semanas.", "Até 24 semanas de gestação, em pacientes com dilatação cervical <4cm e herniação das membranas, sem contração e/ou parto, afastada infecção intramniótica.", "Quando a técnica transabdominal puder ser realizada como alternativa à técnica transvaginal, tendo como principal indicação o prolapso do saco amniótico.", "Com história de uma ou mais perdas gestacionais, com quadro clínico de insuficiência cervical, devendo ser realizada entre 12 e 14 semanas de gravidez, após ultrassonografia revelar feto vivo e sem anomalias."], correctIndex: 2 },
  { id: "amrigs_2023_054", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Considerando as figuras que mostram diferentes formas de utilizar o cinto de segurança durante a gestação, assinale a alternativa que representa a maneira correta de utilizá-lo para evitar traumas graves na mãe e no feto (faixa subabdominal, abaixo do volume uterino, e faixa diagonal entre as mamas, sem cruzar o abdome).", options: ["Opção A.", "Opção B.", "Opção C.", "Opção D."], correctIndex: 0 },
  { id: "amrigs_2023_055", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "O suplemento de ácido fólico previne os defeitos decorrentes do processo de fusão do tubo neural. Essas malformações decorrem da falência do processo normal de fusão do tubo neural que ocorre:", options: ["14 a 21 dias pós-concepção.", "21 a 28 dias pós-concepção.", "28 a 35 dias pós-concepção.", "35 a 42 dias pós-concepção."], correctIndex: 1 },
  { id: "amrigs_2023_056", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Qual tipo de fórceps é indicado para a correção do assinclitismo?", options: ["Simpson.", "Kielland.", "Barton.", "Piper."], correctIndex: 1 },
  { id: "amrigs_2023_057", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "No exame pélvico bimanual, uma imagem apresenta a posição do útero. Considerando a imagem, trata-se de um:", options: ["Toque retal com o útero na posição anteversofletida.", "Toque vaginal com o útero na posição antevertida.", "Toque vaginal com o útero na posição retroversofletida.", "Toque vaginal com o útero na posição antefletida."], correctIndex: 1 },
  { id: "amrigs_2023_058", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Em relação ao acretismo placentário diagnosticado na cesariana de emergência, analise: I. A histerotomia deve ser realizada fora da área placentária. II. A dequitação manual cuidadosa está indicada. III. A histerectomia será realizada com a placenta in situ. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas I e III.", "I, II e III."], correctIndex: 2 },
  { id: "amrigs_2023_059", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Sobre as condições oferecidas pelo modelo fullPIERS, agora sob validação externa, assinale a alternativa correta.", options: ["Não diferencia o alto risco e baixo risco materno para complicações.", "Determina a interrupção da gestação por mais de 7 dias.", "Identifica corretamente o risco de complicações individual de uma gestante com pré-eclâmpsia.", "Diminui o risco da prematuridade causada pela patologia."], correctIndex: 2 },
  { id: "amrigs_2023_060", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "O tratamento das incoordenações uterinas de 1º e 2º graus e da inversão do gradiente uterino no trabalho de parto é: I. Colocação da paciente em decúbito lateral. II. Perfusão de ocitocina e/ou amniorrexe. III. Administração de analgésicos e sedativos. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas I e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_061", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente de 4 anos de idade, previamente hígido, apresenta quadro clínico compatível com meningite aguda. Liquor: pressão de abertura 210mmH2O, celularidade 1.100/μL com predomínio de neutrófilos, glicorraquia 15mg/dL (glicemia 90mg/dL) e proteína 200mg/dL. Trata-se de um caso de meningite:", options: ["Bacteriana aguda.", "Viral.", "Química.", "Fúngica."], correctIndex: 0 },
  { id: "amrigs_2023_062", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Em relação ao Transtorno de Déficit de Atenção e Hiperatividade (TDAH), analise: I. O metilfenidato é agente farmacológico de primeira linha no tratamento do TDAH. II. Os benzodiazepínicos são fármacos indicados no tratamento do TDAH. III. A sua sintomatologia pode persistir inclusive na vida adulta. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 1 },
  { id: "amrigs_2023_063", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "São evidências clínicas de hipertensão intracraniana: I. Papiledema. II. Depressão da consciência. III. Déficits neurológicos focais. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_064", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Um paciente com hemianopsia bitemporal apresenta comprometimento no:", options: ["Lobo temporal.", "Quiasma óptico.", "Trato óptico.", "Lobo parietal."], correctIndex: 1 },
  { id: "amrigs_2023_065", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Neonato com 39 semanas de idade gestacional apresenta desde o nascimento mancha de coloração vinhosa intensa, homogênea, acometendo parte da hemiface esquerda, incluindo região periorbitária. Restante do corpo sem alterações. Com base na possibilidade de associação com síndrome de Sturge-Weber, qual exame complementar é o mais indicado para elucidação diagnóstica?", options: ["Biópsia da lesão.", "Eletroencefalograma de amplitude integrada.", "Tomografia de crânio.", "Angioressonância de crânio."], correctIndex: 3 },
  { id: "amrigs_2023_066", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Segundo a Sociedade Brasileira de Pediatria, o recém-nascido deve ter alta do alojamento conjunto com sua mãe após 48 horas de vida desde que apresente: I. Sinais vitais estáveis por no mínimo 4 horas. II. Eliminações fisiológicas presentes. III. Peso na alta de 2.000g ou mais. IV. Testes de triagem auditiva, do olhinho e do coraçãozinho já realizados. Quais estão corretas?", options: ["Apenas I e III.", "Apenas II e IV.", "Apenas II, III e IV.", "I, II, III e IV."], correctIndex: 1 },
  { id: "amrigs_2023_067", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Qual das alternativas abaixo apresenta um fator de risco para hiperbilirrubinemia mais acentuada no período neonatal?", options: ["Icterícia com início nas primeiras 30 horas de vida.", "Aleitamento materno misto com perda de peso de mais de 6% no momento da alta.", "Idade gestacional menor que 38 semanas ao nascimento.", "História de filho anterior que necessitou de fototerapia."], correctIndex: 3 },
  { id: "amrigs_2023_068", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Um recém-nascido do sexo masculino tem idade gestacional de 38 semanas e 2 dias e, ao nascer, apresenta peso de 2350g, comprimento de 46cm e perímetro cefálico de 32cm (escore-z de peso -1,9276, percentil 2,69, com comprimento e PC também abaixo do percentil 10, pelas tabelas do INTERGROWTH-21). Qual a classificação desse neonato?", options: ["Pré-termo.", "Adequado para a idade gestacional.", "Pequeno para idade gestacional, simétrico.", "Pequeno para a idade gestacional, assimétrico."], correctIndex: 2 },
  { id: "amrigs_2023_069", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "São sinais de irritação meningorradicular encontrados em pacientes, EXCETO:", options: ["Rigidez de nuca.", "Kernig.", "Brudzinki.", "Lázaro."], correctIndex: 3 },
  { id: "amrigs_2023_070", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Em relação aos acidentes na infância, analise: I. No Brasil, acidentes são a causa mais frequente de morte em crianças a partir dos 12 meses de idade. II. Os acidentes variam em sua frequência com idade, ambiente e desenvolvimento da criança. III. Do nascimento aos 9 meses e com peso de até 10kg, a criança pode ser transportada em assentos especiais, de frente para o painel do automóvel, usando cinto de segurança, semi-reclinada. IV. Os andadores, apesar do alto custo e de serem prejudiciais para o desenvolvimento, são aprovados como protetores de acidentes durante o primeiro ano de vida. Quais estão corretas?", options: ["Apenas I e II.", "Apenas II e III.", "Apenas III e IV.", "I, II, III e IV."], correctIndex: 0 },
  { id: "amrigs_2023_071", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 2 meses com história de vômitos, recusa alimentar e irritabilidade é levado ao pronto-socorro. Exame físico: palidez, febre e abaulamento da fontanela anterior. Liquor: celularidade 340 com 82% de polimorfonucleares; proteínas 280mg/dL; glicose 26mg/dL (glicemia 284mg/dL). Qual é o agente etiológico mais provável dessa meningite?", options: ["Escherichia coli.", "Streptococcus pneumoniae.", "Citomegalovírus.", "Staphylococcus aureus."], correctIndex: 0 },
  { id: "amrigs_2023_072", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Considerando a importância de triagem, diagnóstico e gestão sistemática da sepse na criança, assinale V ou F: ( ) Recomenda-se a coleta de hemoculturas antes do tratamento, desde que não atrase a administração de antimicrobianos. ( ) Na prática clínica, a hiperlactatemia é um marcador imprescindível para a suspeita diagnóstica. ( ) A monitorização da saturação O2 e do débito urinário é um importante procedimento da primeira hora. ( ) As respostas endócrinas e metabólicas decorrentes da liberação de citocinas são as principais responsáveis pelas manifestações clínicas e gravidade dos casos. A ordem correta, de cima para baixo, é:", options: ["V – F – V – V.", "F – V – F – V.", "F – V – V – F.", "V – F – V – F."], correctIndex: 0 },
  { id: "amrigs_2023_073", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Em relação à Parada Cardiorrespiratória (PCR) na faixa etária pediátrica, assinale V ou F: ( ) As causas cardiológicas primárias são as que mais comumente levam à PCR em crianças. ( ) As vias de acesso preferenciais para administração de medicamentos são a endovenosa e a intraóssea. ( ) A epinefrina é a droga padrão a ser utilizada. ( ) Controle da hipertermia e hipoxemia são medidas importantes no tratamento pós-ressuscitação. A ordem correta, de cima para baixo, é:", options: ["F – V – V – V.", "V – V – V – F.", "F – F – V – V.", "V – V – F – F."], correctIndex: 0 },
  { id: "amrigs_2023_074", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 2 meses de idade é trazido pela mãe para consulta de puericultura, referindo 'vômitos' após as mamadas. Nasceu a termo, sem fatores de risco, aleitamento materno exclusivo, crescimento e desenvolvimento adequados, sem eventos clínicos significativos. Em relação à queixa da mãe, o procedimento indicado é:", options: ["Tranquilizar a mãe e manter o aleitamento materno exclusivo.", "Prescrever fórmula antirrefluxo.", "Prescrever ranitidina.", "Solicitar pHmetria esofágica."], correctIndex: 0 },
  { id: "amrigs_2023_075", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Considerando o instrumento para vigilância do desenvolvimento da Caderneta da Criança do Ministério da Saúde, é esperado que durante o primeiro ano de vida uma criança desenvolva habilidades de buscar ativamente objetos, transferir objetos de uma mão para outra, fazer pinça completa e produzir jargão, respectivamente, entre as faixas etárias de:", options: ["4 e 6 meses; 6 e 9 meses; 9 e 12 meses; 6 e 9 meses.", "6 e 9 meses; 4 e 6 meses; 6 e 9 meses; 9 e 12 meses.", "6 e 9 meses; 4 e 6 meses; 6 e 9 meses; 6 e 9 meses.", "4 e 6 meses; 6 e 9 meses; 9 e 12 meses; 9 e 12 meses."], correctIndex: 3 },
  { id: "amrigs_2023_076", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 5 anos, residente em área com alta prevalência de dengue, consulta por febre, náuseas, vômitos, dor abdominal, cefaleia e mialgias. Prova do laço positiva; fígado palpável 4cm abaixo do rebordo costal direito; hipótese diagnóstica de dengue. Considerando o quadro, a conduta recomendada é o acompanhamento:", options: ["Ambulatorial.", "Em leito de observação.", "Em leito de internação.", "Em leito de emergência."], correctIndex: 2 },
  { id: "amrigs_2023_077", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "No atraso puberal secundário às síndromes de Turner e Klinefelter, temos hipogonadismo, respectivamente:", options: ["Hipogonadotrófico e hipergonadotrófico.", "Hipergonadotrófico e hipergonadotrófico.", "Hipergonadotrófico e hipogonadotrófico.", "Hipogonadotrófico e hipogonadotrófico."], correctIndex: 1 },
  { id: "amrigs_2023_078", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 12 meses dá entrada na emergência pediátrica em coma afebril, há 3 dias mais irritada e com redução da aceitação da dieta. Hidratada, corada, respiração típica de Kussmaul, sem déficit perfusional, hemoglicoteste 600mg/dL. Gasometria: acidemia metabólica com anion gap aumentado. Cuidados devem ser tomados para evitar baixo débito e PCR pela hipofosfatemia decorrente de:", options: ["Hipoinsulinismo primário do coma hiperosmolar diabético, já que cetoacidose não pode ser definida em função da faixa etária.", "Hiperinsulinismo induzido pelo tratamento, à semelhança do que ocorre na síndrome de realimentação.", "Correção da acidemia severa com bicarbonato intravenoso, fármaco esse utilizado independentemente da gravidade da acidemia.", "Hipercalcemia comum na cetoacidose diabética, especialmente se a criança apresentar sinal de Trousseau positivo."], correctIndex: 1 },
  { id: "amrigs_2023_079", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "A insuficiência respiratória na sepse por Epstein-Barr na infância pode se apresentar em decorrência de:", options: ["Hipoxemia inicial com hipercapnia, secundárias especialmente à obstrução extrínseca de vias aéreas por linfadenopatia cervical.", "Hipercapnia sem hipoxemia, pois existe comprometimento parenquimatoso pulmonar, dificultando mais a difusão de CO2 do que do O2.", "Hipoxemia isolada sem risco de restrição de caixa torácica, já que essa situação não cursa com hepatoesplenomegalia.", "Aumento da relação ventilação/perfusão por obstrução brônquica, fenômeno conhecido por efeito espaço-morto."], correctIndex: 0 },
  { id: "amrigs_2023_080", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 8 anos foi atendido em pronto atendimento por fratura do rádio após cair de uma árvore. A mãe relata que ele é bastante inquieto, 'barulhento', conversador, perturba a aula, tem dificuldades em realizar tarefas por descuido, distrai-se com facilidade, precisa ser chamado ou acenado pois parece não ouvir, tem problemas de concentração no futebol, esquece materiais e perde suas coisas. QI na faixa normal. Considerando o caso de TDAH, qual é o diagnóstico mais provável?", options: ["TDAH, tipo predominante hiperativo.", "TDAH, tipo predominante desatento.", "TDAH, tipo combinado.", "TDAH com comorbidade de Transtorno de Oposição Desafiante (TOD)."], correctIndex: 2 },
  { id: "amrigs_2023_081", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação aos princípios do SUS, analise: I. Descentralização refere-se a níveis de complexidade tecnológica crescente. II. Participação social refere-se à participação da população no processo de formulação das políticas de saúde. III. Complementação do setor privado refere-se à contratação de serviços privados, quando o setor público não for suficiente. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 2 },
  { id: "amrigs_2023_082", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Analise, em relação à Equipe de Saúde da Família, conforme a Política de Atenção Básica: I. É considerada como estratégia de expansão, qualificação e consolidação da Atenção Básica. II. O número de agentes comunitários de saúde por equipe deverá ser definido conforme critérios locais, recomendando-se cobertura de 100% da população com número máximo de 750 pessoas por ACS. III. É composta no mínimo por médico, enfermeiro, auxiliar/técnico de enfermagem, cirurgião-dentista, auxiliar/técnico em saúde bucal e agente comunitário de saúde. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 0 },
  { id: "amrigs_2023_083", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "São atribuições comuns a todos os membros das equipes de saúde que atuam na Atenção Básica:", options: ["Realizar estratificação de risco e elaborar plano de cuidados para pessoas com condições crônicas, junto aos demais membros da equipe.", "Participar do processo de territorialização e mapeamento da área de atuação da equipe, identificando grupos, famílias e indivíduos expostos a riscos e vulnerabilidades.", "Encaminhar, quando necessário, usuários a outros pontos de atenção, mantendo sob sua responsabilidade o acompanhamento do plano terapêutico prescrito.", "Realizar e/ou supervisionar acolhimento com escuta qualificada e classificação de risco, de acordo com protocolos estabelecidos."], correctIndex: 1 },
  { id: "amrigs_2023_084", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Assinale a alternativa que apresenta casos que se enquadram em situação de notificação compulsória imediata no Brasil.", options: ["Tuberculose e leishmaniose visceral.", "Doença de Chagas crônica e esquistossomose.", "Febre amarela e botulismo.", "Hanseníase e hepatites virais."], correctIndex: 2 },
  { id: "amrigs_2023_085", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Analise, em relação à Portaria nº 373/2002 que aprova a Norma Operacional da Assistência à Saúde (NOAS-SUS 01/2002): I. Amplia as responsabilidades dos municípios na Atenção Básica. II. Estabelece o processo de regionalização como estratégia de hierarquização dos serviços de saúde e de busca de maior equidade. III. Cria mecanismos para o fortalecimento da capacidade de gestão do Sistema Único de Saúde. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_086", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Homem de 56 anos, previamente hígido, deseja fazer consulta de revisão periódica na UBS do seu bairro. Entretanto, como trabalha formalmente de segunda à sexta-feira das 8h às 17h, não consegue ir, pois a UBS não tem horário estendido. Qual dos atributos da Atenção Primária à Saúde (APS) não está sendo ofertado nessa situação?", options: ["Longitudinalidade.", "Acessibilidade.", "Integralidade.", "Coordenação."], correctIndex: 1 },
  { id: "amrigs_2023_087", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Analise, em relação à APS: I. Tem a função de servir e coordenar todas as necessidades de saúde da pessoa, assumindo responsabilidade pela continuidade e pelo acompanhamento individual e por problemas de saúde da comunidade. II. A coordenação do cuidado pode ser verificada, por exemplo, quando a equipe da APS faz contato com a equipe de um hospital terciário sobre internações por Covid-19 e previsões de alta para iniciar atenção domiciliar. III. Taxas elevadas de internações hospitalares por condições sensíveis podem indicar baixo acesso aos serviços de APS ou oferta de APS de baixa qualidade. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_088", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a alternativa correta em relação ao diagnóstico e tratamento da sífilis na APS.", options: ["O VDRL é um exame treponêmico e serve para o diagnóstico e acompanhamento pós-terapêutico.", "O VDRL passa a ser positivo após a 2ª semana do aparecimento do cancro duro e costuma atingir seus valores mais elevados na fase secundária.", "A aplicação da penicilina benzatina não deve ser realizada na UBS, pelo risco da reação anafilática à penicilina.", "O tratamento da sífilis latente tardia, com mais de um ano de evolução (ou latente com duração ignorada), e da sífilis terciária é feito com benzilpenicilina benzatina 2,4 milhões de UI, intramuscular, em dose única."], correctIndex: 1 },
  { id: "amrigs_2023_089", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Analise, em relação ao sofrimento psíquico: I. Estudos avaliando a saúde mental da população LGBTQIA+, negros e mulheres demonstram que esses indivíduos têm risco elevado para desenvolver sofrimento psíquico e transtornos mentais. II. Sofrimento psíquico em questões relacionadas à raça, gênero, indígenas e refugiados deve ser avaliado em serviços especializados. III. É fundamental manter-se alerta em situações de sofrimento mental, queixas somáticas inespecíficas e atrasos para consultas ou dificuldade de acesso diante do impacto dos papéis de gênero e da violência doméstica na saúde mental dos pacientes. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 1 },
  { id: "amrigs_2023_090", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Analise, no que se refere às ações de controle da tuberculose a serem realizadas: I. Compete à instância municipal, entre outras ações, assegurar a realização dos exames diagnósticos, identificar e organizar a rede de laboratórios locais e suas referências. II. A organização da assistência farmacêutica na APS e o uso racional de medicamentos devem incluir acesso, atenção farmacêutica, uso de novos medicamentos e ações de farmacovigilância. III. Deve haver registro periódico e sistematizado da dispensação de medicamentos, podendo ser usado como método indireto de controle de adesão. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2023_091", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Sobre o Transtorno do Espectro Autista (TEA), pode-se afirmar que:", options: ["Evidências científicas apontam a presença de um biomarcador específico.", "O mercúrio presente nas vacinas é um importante fator de risco para o desenvolvimento do TEA.", "O diagnóstico é essencialmente clínico, feito a partir das observações da criança, entrevistas com os pais e aplicação de instrumentos específicos.", "A presença de estereotipias e afeto restrito causam pouco prejuízo no processo de socialização."], correctIndex: 2 },
  { id: "amrigs_2023_092", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Para identificar indivíduos com taquicardia (FC>100bpm), um pesquisador está utilizando um monitor cardíaco de pulso que está com defeito, e sempre mostra valores menores que 100bpm, medindo corretamente apenas os indivíduos com frequência cardíaca normal. Considerando essas informações, a sensibilidade desse monitor cardíaco é:", options: ["De 100%, e a especificidade é zero.", "De 50%, e a especificidade é 50%.", "De zero, e a especificidade é 100%.", "De zero, e a especificidade também é zero."], correctIndex: 2 },
  { id: "amrigs_2023_093", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Considere que o risco de uma mãe de 40 anos ter um bebê com síndrome de Down seja de 1%, que a sensibilidade de um teste feito no trimestre inicial da gestação seja de 90% e a taxa de falsos positivos seja de 5% (o exame identifica corretamente 95% de bebês sem síndrome de Down). Supondo um resultado positivo nesse teste, qual é a probabilidade de que o bebê realmente tenha síndrome de Down?", options: ["Entre 10% e 20%.", "Entre 45% e 55%.", "Entre 85% e 95%.", "Entre 95% e 100%."], correctIndex: 0 },
  { id: "amrigs_2023_094", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um estudo avaliou a associação entre sedentarismo e algumas condições de saúde entre homens e mulheres, com riscos relativos (IC95%) para obesidade (1,22 e 1,28, ambos com IC excluindo 1), diabetes (0,98 e 1,03, IC incluindo 1), hipertensão (1,07 em homens com IC excluindo 1; 0,99 em mulheres com IC incluindo 1), osteoporose (IC incluindo 1 em ambos) e depressão (1,16 e 1,10, ambos com IC excluindo 1). Podemos afirmar que o sedentarismo está significativamente associado ao risco de:", options: ["Obesidade e diabetes em homens e mulheres.", "Hipertensão somente em mulheres.", "Osteoporose em homens e mulheres.", "Depressão em homens e mulheres."], correctIndex: 3 },
  { id: "amrigs_2023_095", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "A medida que expressa quantas vezes mais (ou menos) é provável encontrar um resultado em pessoas doentes, em comparação com as não doentes, e cujo resultado influencia a probabilidade pós-teste é chamada de:", options: ["Especificidade.", "Razão de verossimilhança.", "Sensibilidade.", "Valor preditivo."], correctIndex: 1 },
  { id: "amrigs_2023_096", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Qual dos resultados abaixo apresenta a maior precisão?", options: ["Média: 3.050g; desvio-padrão: 200g.", "Média: 3.150g; desvio-padrão: 350g.", "Média: 3.200g; desvio-padrão: 100g.", "Média: 3.300g; desvio-padrão: 250g."], correctIndex: 2 },
  { id: "amrigs_2023_097", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um pesquisador pretende estudar a prevalência de uma doença comum e uma doença rara na mesma população. Como deve ser a amostra?", options: ["Para estudar a doença comum, a amostra deve ser menor do que a utilizada para estudar a doença rara.", "Para estudar a doença comum, a amostra deve ser maior do que a utilizada para estudar a doença rara.", "Para estudar a doença comum, a amostra deve ser igual à utilizada para estudar a doença rara.", "Não é possível definir com as informações fornecidas."], correctIndex: 0 },
  { id: "amrigs_2023_099", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "De acordo com as normas de publicidade médica do Código de Ética Médica nº 2.217/2018, é vedado ao médico: I. Permitir que sua participação na divulgação de assuntos médicos, em qualquer meio de comunicação de massa, deixe de ter caráter exclusivamente de esclarecimento e educação da sociedade. II. Divulgar informação sobre assunto médico de forma sensacionalista, promocional ou de conteúdo inverídico. III. Divulgar, fora do meio científico, processo de tratamento ou descoberta cujo valor ainda não esteja expressamente reconhecido cientificamente por órgão competente. IV. Participar de anúncios de empresas comerciais, qualquer que seja sua natureza, valendo-se de sua profissão. Quais estão corretas?", options: ["Apenas I e II.", "Apenas II e III.", "Apenas III e IV.", "I, II, III e IV."], correctIndex: 3 },
  { id: "amrigs_2023_100", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Analise, em relação à saúde mental e às doenças orgânicas: I. O hipotireoidismo causa sintomas comuns à depressão, como cansaço, alteração do sono, ganho de peso, desânimo e fraqueza. II. Pacientes com dor crônica apresentam frequentemente comorbidade psiquiátrica. III. A doença de Parkinson pode apresentar comorbidade com depressão em até 50% dos pacientes acometidos. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
];
